// frontend/src/pages/Payments.js
import { useEffect, useMemo, useState } from "react";
import api from "../api";
import { useAuth } from "../AuthContext";

/* ===== Helpers ===== */
const VND = (v) => Number(v || 0).toLocaleString("vi-VN");
const todayStr = () => {
    const d = new Date();
    const m = String(d.getMonth() + 1).padStart(2, "0");
    const day = String(d.getDate()).padStart(2, "0");
    return `${d.getFullYear()}-${m}-${day}`;
};
const parseNumberText = (s) =>
    Number(String(s ?? "").replace(/[^\d]/g, "") || 0);

const METHOD_OPTS = [
    { label: "Chuyển khoản", value: "BANK_TRANSFER" },
    { label: "Tiền mặt", value: "CASH" },
    { label: "Khác", value: "OTHER" },
];
const STATUS_OPTS = [
    { label: "Chưa thanh toán", value: "UNPAID" },
    { label: "Đã thanh toán", value: "PAID" },
];
const toLabel = (opts, v) =>
    opts.find((o) => o.value === v || o.label === v)?.label || v || "";
const toValue = (opts, l) =>
    opts.find((o) => o.label === l || o.value === l)?.value || l;

function hasAnyRole(user, allow = []) {
    if (!user) return false;
    const S = new Set();
    const add = (x) => {
        if (!x) return;
        if (Array.isArray(x)) return x.forEach(add);
        if (typeof x === "string") return S.add(x.toUpperCase());
        if (typeof x === "object")
            return ["role", "name", "authority"].forEach(
                (k) => x[k] && S.add(String(x[k]).toUpperCase())
            );
    };
    add(user?.role);
    add(user?.roles);
    add(user?.authorities);
    return allow.some((r) => S.has(r));
}

/* ===== Tiny toast ===== */
function Toast({ show, type = "success", children, onClose }) {
    if (!show) return null;
    const tone =
        type === "error"
            ? "bg-rose-600"
            : type === "warn"
                ? "bg-amber-600"
                : "bg-emerald-600";
    return (
        <div className="fixed top-4 right-4 z-[60]">
            <div className={`${tone} text-white px-4 py-2 rounded-lg shadow-lg`}>
                <div className="flex items-center gap-3">
                    <span className="text-sm">{children}</span>
                    <button
                        className="text-white/80 hover:text-white text-xs"
                        onClick={onClose}
                    >
                        Đóng
                    </button>
                </div>
            </div>
        </div>
    );
}

/* ===== Main Page: Cards per Contract ===== */
export default function Payments() {
    const { user } = useAuth();
    const canCreate = hasAnyRole(user, ["ADMIN", "SALES"]);
    const canMarkPaid = hasAnyRole(user, ["ADMIN", "ACCOUNTANT"]);
    const canDelete = hasAnyRole(user, ["ADMIN", "ACCOUNTANT"]);
    const canView = hasAnyRole(user, ["ADMIN", "ACCOUNTANT", "SALES"]);

    const [contracts, setContracts] = useState([]);
    const [expanded, setExpanded] = useState(() => new Set()); // contractId set
    const [paymentsMap, setPaymentsMap] = useState({}); // contractId -> payments[]
    const [loadingMap, setLoadingMap] = useState({});
    const [q, setQ] = useState("");
    const [toast, setToast] = useState({ show: false, type: "success", msg: "" });

    const openToast = (msg, type = "success") =>
        setToast({ show: true, type, msg });
    const closeToast = () => setToast((t) => ({ ...t, show: false }));

    useEffect(() => {
        loadContracts();
    }, []);

    async function loadContracts() {
        try {
            const { data } = await api.get("/api/contracts", {
                params: { page: 0, size: 200, sort: "id,desc" },
            });
            const list = Array.isArray(data) ? data : data?.content || [];
            setContracts(
                list.map((c) => ({
                    id: c.id,
                    code: c.contractCode || c.code || `HD-${c.id}`,
                    name: c.name || c.title || c.contractName || "",
                    customer: c.customer?.name || c.customerName || "-",
                    status: c.status || "UNKNOWN",
                    totalAmount: c.totalAmount ?? c.total_value ?? 0,
                    totalPaid: c.totalPaid ?? c.paid_value ?? 0,
                }))
            );
        } catch (e) {
            console.error(e);
            openToast("Tải danh sách hợp đồng thất bại", "error");
        }
    }

    function toggleExpand(id) {
        const next = new Set(expanded);
        if (next.has(id)) next.delete(id);
        else {
            next.add(id);
            if (!paymentsMap[id]) fetchPaymentsByContract(id);
        }
        setExpanded(next);
    }

    async function fetchPaymentsByContract(contractId) {
        setLoadingMap((m) => ({ ...m, [contractId]: true }));
        try {
            const { data } = await api.get(`/api/payments/by-contract/${contractId}`);
            setPaymentsMap((m) => ({
                ...m,
                [contractId]: Array.isArray(data) ? data : data?.content ?? [],
            }));
        } catch (e) {
            console.error(e);
            openToast("Tải đợt thanh toán thất bại", "error");
        } finally {
            setLoadingMap((m) => ({ ...m, [contractId]: false }));
        }
    }

    async function addPayment(contractId, payload, onDone) {
        try {
            await api.post(`/api/payments/by-contract/${contractId}`, payload);
            await fetchPaymentsByContract(contractId);
            await loadContracts(); // refresh progress
            onDone?.();
            openToast("Đã thêm đợt thanh toán");
        } catch (e) {
            console.error(e);
            openToast("Thêm đợt thanh toán thất bại", "error");
        }
    }

    async function markPaid(contractId, paymentId, actualAmount, paidDate, method, note, onDone) {
        try {
            await api.patch(`/api/payments/${paymentId}/mark-paid`, {
                actualAmount: actualAmount ?? null,
                paidDate: paidDate || todayStr(),
                method: toValue(METHOD_OPTS, method),
                note: note?.trim() || null,
            });
            await fetchPaymentsByContract(contractId);
            await loadContracts();
            onDone?.();
            openToast("Cập nhật: Đã thanh toán");
        } catch (e) {
            console.error(e);
            openToast("Đánh dấu đã thu thất bại", "error");
        }
    }

    async function deletePayment(contractId, paymentId) {
        if (!canDelete) return;
        if (!window.confirm("Xóa đợt thanh toán này? (Chỉ xoá khi CHƯA THU)")) return;
        try {
            await api.delete(`/api/payments/${paymentId}`);
            await fetchPaymentsByContract(contractId);
            await loadContracts();
            openToast("Đã xóa đợt thanh toán");
        } catch (e) {
            console.error(e);
            openToast("Xóa đợt thanh toán thất bại", "error");
        }
    }

    const filtered = useMemo(() => {
        if (!q.trim()) return contracts;
        const key = q.toLowerCase();
        return contracts.filter(
            (c) =>
                c.code.toLowerCase().includes(key) ||
                c.customer.toLowerCase().includes(key) ||
                (c.name || "").toLowerCase().includes(key)
        );
    }, [contracts, q]);

    if (!canView) {
        return (
            <div className="space-y-3">
                <h2 className="text-lg font-semibold">Thanh toán</h2>
                <p className="text-sm text-slate-500">Bạn không có quyền xem trang này.</p>
            </div>
        );
    }

    return (
        <div className="p-6 space-y-6">
            <Toast show={toast.show} type={toast.type} onClose={closeToast}>
                {toast.msg}
            </Toast>

            {/* Header + search */}
            <div className="flex items-center justify-between gap-3">
                <div>
                    <h1 className="text-2xl font-semibold">Đợt & Lịch sử thanh toán</h1>
                    <p className="text-sm text-slate-500">Mỗi hợp đồng là một hộp riêng.</p>
                </div>
                <div className="relative w-full max-w-md">
                    <input
                        value={q}
                        onChange={(e) => setQ(e.target.value)}
                        placeholder="Tìm hợp đồng… (mã / tên / khách hàng)"
                        className="w-full pl-3 pr-3 py-2 rounded-xl border border-indigo-100 bg-white shadow"
                    />
                </div>
            </div>

            {/* Cards per contract */}
            {filtered.length === 0 ? (
                <div className="text-slate-500">Không có hợp đồng phù hợp.</div>
            ) : (
                <div className="space-y-4">
                    {filtered.map((c) => {
                        const isOpen = expanded.has(c.id);
                        const pct =
                            c.totalAmount > 0
                                ? Math.min(100, Math.round(((c.totalPaid || 0) / c.totalAmount) * 100))
                                : 0;

                        return (
                            <div
                                key={c.id}
                                className="rounded-2xl border border-indigo-100 bg-white shadow-sm overflow-hidden"
                            >
                                {/* Header */}
                                <button
                                    onClick={() => toggleExpand(c.id)}
                                    className="w-full text-left p-4 hover:bg-indigo-50/40 flex items-center justify-between"
                                >
                                    <div>
                                        <div className="font-semibold">
                                            {c.code} — {c.customer}
                                        </div>
                                        {c.name && <div className="text-sm text-slate-500">{c.name}</div>}
                                    </div>
                                    <div className="text-right">
                                        <div className="text-xs text-slate-500">Đã thu / Tổng</div>
                                        <div className="font-medium tabular-nums">
                                            {VND(c.totalPaid)} / {VND(c.totalAmount)} đ ({pct}%)
                                        </div>
                                    </div>
                                </button>

                                {/* Progress */}
                                <div className="px-4 pb-4">
                                    <div className="w-full h-2 bg-slate-200 rounded-full overflow-hidden">
                                        <div
                                            className="h-full bg-emerald-500"
                                            style={{ width: `${pct}%` }}
                                        />
                                    </div>
                                </div>

                                {/* Body */}
                                {isOpen && (
                                    <div className="px-4 pb-5">
                                        <div className="flex flex-col lg:flex-row gap-4">
                                            {/* Payments list */}
                                            <div className="flex-1 rounded-xl border border-indigo-100">
                                                <div className="px-3 py-2 border-b bg-indigo-50 rounded-t-xl text-sm font-medium">
                                                    Các đợt thanh toán
                                                </div>

                                                {loadingMap[c.id] ? (
                                                    <div className="p-4 text-slate-500">Đang tải…</div>
                                                ) : (paymentsMap[c.id] || []).length === 0 ? (
                                                    <div className="p-4 text-slate-500">Chưa có đợt nào.</div>
                                                ) : (
                                                    <div className="overflow-x-auto">
                                                        <table className="min-w-full text-sm">
                                                            <thead className="bg-slate-50 text-slate-600">
                                                            <tr>
                                                                <th className="px-4 py-2 text-left">#</th>
                                                                <th className="px-4 py-2 text-left">Ngày trả / dự kiến</th>
                                                                <th className="px-4 py-2 text-left">Số tiền</th>
                                                                <th className="px-4 py-2 text-left">Phương thức</th>
                                                                <th className="px-4 py-2 text-left">Trạng thái</th>
                                                                <th className="px-4 py-2 text-left">Ghi chú</th>
                                                                <th className="px-4 py-2 text-right">Thao tác</th>
                                                            </tr>
                                                            </thead>
                                                            <tbody className="divide-y">
                                                            {(paymentsMap[c.id] || []).map((p, idx) => {
                                                                const method = p.method || p.paymentMethod;
                                                                const statusValue = String(
                                                                    p.status || p.paymentStatus || "UNPAID"
                                                                ).toUpperCase();
                                                                const isPaid = statusValue === "PAID";
                                                                const dateDisplay = p.paymentDate ?? p.dueDate ?? "-";

                                                                return (
                                                                    <tr key={p.id} className="hover:bg-indigo-50/30">
                                                                        <td className="px-4 py-2">{idx + 1}</td>
                                                                        <td className="px-4 py-2">{dateDisplay}</td>
                                                                        <td className="px-4 py-2 tabular-nums">
                                                                            {VND(p.amount ?? 0)} đ
                                                                        </td>
                                                                        <td className="px-4 py-2">
                                                                            {toLabel(METHOD_OPTS, method) || "-"}
                                                                        </td>
                                                                        <td className="px-4 py-2">
                                        <span
                                            className={
                                                "px-2 py-0.5 rounded-full text-xs " +
                                                (isPaid
                                                    ? "bg-emerald-100 text-emerald-700"
                                                    : "bg-amber-100 text-amber-700")
                                            }
                                        >
                                          {toLabel(STATUS_OPTS, statusValue)}
                                        </span>
                                                                        </td>
                                                                        <td className="px-4 py-2 max-w-[260px] truncate" title={p.note || ""}>
                                                                            {p.note || "-"}
                                                                        </td>
                                                                        <td className="px-4 py-2 text-right">
                                                                            <div className="inline-flex gap-2">
                                                                                {!isPaid && canMarkPaid && (
                                                                                    <MarkPaidInline
                                                                                        onConfirm={(actual, paidDate, methodLabel, note) =>
                                                                                            markPaid(
                                                                                                c.id,
                                                                                                p.id,
                                                                                                actual,
                                                                                                paidDate,
                                                                                                methodLabel,
                                                                                                note
                                                                                            )
                                                                                        }
                                                                                        defaultAmount={p.actualAmount ?? p.amount ?? 0}
                                                                                    />
                                                                                )}
                                                                                {!isPaid && canDelete && (
                                                                                    <button
                                                                                        onClick={() => deletePayment(c.id, p.id)}
                                                                                        className="px-2 py-1 rounded bg-rose-50 text-rose-700 hover:bg-rose-100"
                                                                                    >
                                                                                        Xóa
                                                                                    </button>
                                                                                )}
                                                                                {isPaid && <span className="text-slate-400">—</span>}
                                                                            </div>
                                                                        </td>
                                                                    </tr>
                                                                );
                                                            })}
                                                            </tbody>
                                                        </table>
                                                    </div>
                                                )}
                                            </div>

                                            {/* Add payment (right column) */}
                                            {canCreate && (
                                                <div className="w-full lg:w-80 shrink-0 rounded-xl border border-indigo-100">
                                                    <div className="px-3 py-2 border-b bg-indigo-50 rounded-t-xl text-sm font-medium">
                                                        Thêm đợt thanh toán
                                                    </div>
                                                    <AddPaymentForm
                                                        onSubmit={(payload, done) =>
                                                            addPayment(c.id, payload, done)
                                                        }
                                                    />
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                )}

                                {/* Auto fetch when first opening */}
                                {isOpen && !paymentsMap[c.id] && !loadingMap[c.id] && (
                                    <div className="px-4 pb-5">
                                        <button
                                            onClick={() => fetchPaymentsByContract(c.id)}
                                            className="px-3 py-2 rounded-lg border hover:bg-slate-50"
                                        >
                                            Tải danh sách đợt
                                        </button>
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </div>
            )}
        </div>
    );
}

/* ===== Add Payment Inline Form ===== */
function AddPaymentForm({ onSubmit }) {
    const [amountText, setAmountText] = useState("");
    const [dueDate, setDueDate] = useState(todayStr());
    const [method, setMethod] = useState("Chuyển khoản");
    const [note, setNote] = useState("");
    const [saving, setSaving] = useState(false);

    async function handleSubmit(e) {
        e.preventDefault();
        const amount = parseNumberText(amountText);
        if (!amount || amount <= 0) {
            alert("Nhập số tiền > 0");
            return;
        }
        setSaving(true);
        const payload = {
            amount,
            dueDate: dueDate || null,
            method: toValue(METHOD_OPTS, method),
            note: note?.trim() || null,
        };
        await onSubmit(payload, () => {
            setAmountText("");
            setDueDate(todayStr());
            setMethod("Chuyển khoản");
            setNote("");
        });
        setSaving(false);
    }

    return (
        <form onSubmit={handleSubmit} className="p-4 space-y-3">
            <div className="space-y-1">
                <label className="text-sm text-slate-600">Số tiền (đ)</label>
                <input
                    type="text"
                    inputMode="numeric"
                    pattern="[0-9\.]*"
                    placeholder="VD: 200.000.000"
                    value={amountText}
                    onChange={(e) =>
                        setAmountText(
                            e.target.value
                                .replace(/[^\d]/g, "")
                                .replace(/\B(?=(\d{3})+(?!\d))/g, ".")
                        )
                    }
                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow tabular-nums"
                />
            </div>
            <div className="space-y-1">
                <label className="text-sm text-slate-600">Ngày dự kiến thu</label>
                <input
                    type="date"
                    value={dueDate}
                    onChange={(e) => setDueDate(e.target.value)}
                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                />
            </div>
            <div className="space-y-1">
                <label className="text-sm text-slate-600">Phương thức</label>
                <select
                    value={method}
                    onChange={(e) => setMethod(e.target.value)}
                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                >
                    {METHOD_OPTS.map((o) => (
                        <option key={o.value} value={o.label}>
                            {o.label}
                        </option>
                    ))}
                </select>
            </div>
            <div className="space-y-1">
                <label className="text-sm text-slate-600">Ghi chú</label>
                <input
                    placeholder="VD: Thu đợt 1"
                    value={note}
                    onChange={(e) => setNote(e.target.value)}
                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                />
            </div>
            <button
                type="submit"
                disabled={saving}
                className="w-full px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700 disabled:opacity-50"
            >
                {saving ? "Đang lưu..." : "Thêm đợt"}
            </button>
        </form>
    );
}

/* ===== Mark Paid Inline (small popover) ===== */
function MarkPaidInline({ defaultAmount, onConfirm }) {
    const [open, setOpen] = useState(false);
    const [paidDate, setPaidDate] = useState(todayStr());
    const [method, setMethod] = useState("Chuyển khoản");
    const [note, setNote] = useState("");

    async function submit() {
        await onConfirm(defaultAmount, paidDate, method, note);
        setOpen(false);
    }

    return (
        <div className="relative inline-block">
            {!open ? (
                <button
                    onClick={() => setOpen(true)}
                    className="px-2 py-1 rounded bg-emerald-50 text-emerald-700 hover:bg-emerald-100"
                >
                    Đã thu
                </button>
            ) : (
                <div className="absolute z-10 right-0 mt-2 w-72 rounded-xl border border-indigo-100 bg-white shadow-lg p-3">
                    <div className="text-sm font-medium mb-2">Xác nhận đã thu</div>
                    <div className="text-xs text-slate-500 mb-2">
                        Số tiền thực thu: <b>{VND(defaultAmount)} đ</b>
                    </div>
                    <div className="space-y-2">
                        <div>
                            <label className="text-xs text-slate-600">Ngày thu</label>
                            <input
                                type="date"
                                value={paidDate}
                                onChange={(e) => setPaidDate(e.target.value)}
                                className="w-full px-2 py-1.5 rounded-lg border border-indigo-100 bg-white shadow"
                            />
                        </div>
                        <div>
                            <label className="text-xs text-slate-600">Phương thức</label>
                            <select
                                value={method}
                                onChange={(e) => setMethod(e.target.value)}
                                className="w-full px-2 py-1.5 rounded-lg border border-indigo-100 bg-white shadow"
                            >
                                {METHOD_OPTS.map((o) => (
                                    <option key={o.value} value={o.label}>
                                        {o.label}
                                    </option>
                                ))}
                            </select>
                        </div>
                        <div>
                            <label className="text-xs text-slate-600">Ghi chú</label>
                            <input
                                value={note}
                                onChange={(e) => setNote(e.target.value)}
                                className="w-full px-2 py-1.5 rounded-lg border border-indigo-100 bg-white shadow"
                                placeholder="VD: Thu đủ đợt 2"
                            />
                        </div>
                        <div className="flex items-center justify-end gap-2">
                            <button
                                className="px-3 py-1.5 rounded-lg bg-slate-100 hover:bg-slate-200"
                                onClick={() => setOpen(false)}
                            >
                                Hủy
                            </button>
                            <button
                                className="px-3 py-1.5 rounded-lg bg-emerald-600 text-white hover:bg-emerald-700"
                                onClick={submit}
                            >
                                Xác nhận
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}
